// App.js
import React, { useState, useEffect, useCallback, useRef } from 'react';
import {
  View,
  Text,
  TouchableOpacity,
  StyleSheet,
  ActivityIndicator,
  Alert,
  ScrollView,
  Linking,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import * as AuthSession from 'expo-auth-session';
import * as WebBrowser from 'expo-web-browser';

WebBrowser.maybeCompleteAuthSession();

// ============================================================
// WARNING: Storing client_secret in a mobile app is a security
// risk. Mobile apps are considered "public clients" in OAuth 2.0
// and should use PKCE (Proof Key for Code Exchange) without a
// client_secret. The client_secret can be extracted from the app
// binary through reverse engineering. Consider using:
// 1. Authorization Code Flow with PKCE (no client_secret)
// 2. A backend proxy to handle token exchange
// ============================================================

// OAuth 2.0 Configuration
const OAUTH_CONFIG = {
  clientId: 'your-client-id-here',
  clientSecret: 'your-client-secret-here', // SECURITY RISK: See warning above
  authorizationEndpoint: 'https://your-oauth-server.com/authorize',
  tokenEndpoint: 'https://your-oauth-server.com/token',
  revocationEndpoint: 'https://your-oauth-server.com/revoke',
  userInfoEndpoint: 'https://your-oauth-server.com/userinfo',
  scopes: ['openid', 'profile', 'email', 'offline_access'],
  redirectUri: AuthSession.makeRedirectUri({
    scheme: 'myapp',
    path: 'callback',
  }),
};

// Storage keys
const STORAGE_KEYS = {
  ACCESS_TOKEN: '@oauth_access_token',
  REFRESH_TOKEN: '@oauth_refresh_token',
  TOKEN_EXPIRY: '@oauth_token_expiry',
  USER_INFO: '@oauth_user_info',
};

// Token refresh buffer (refresh 5 minutes before expiry)
const TOKEN_REFRESH_BUFFER_SECONDS = 300;

// Token Manager Class
class TokenManager {
  static async storeTokens(accessToken, refreshToken, expiresIn) {
    const expiryTime = Date.now() + expiresIn * 1000;
    try {
      await AsyncStorage.multiSet([
        [STORAGE_KEYS.ACCESS_TOKEN, accessToken],
        [STORAGE_KEYS.REFRESH_TOKEN, refreshToken || ''],
        [STORAGE_KEYS.TOKEN_EXPIRY, expiryTime.toString()],
      ]);
      return { accessToken, refreshToken, expiryTime };
    } catch (error) {
      console.error('Failed to store tokens:', error);
      throw error;
    }
  }

  static async getTokens() {
    try {
      const values = await AsyncStorage.multiGet([
        STORAGE_KEYS.ACCESS_TOKEN,
        STORAGE_KEYS.REFRESH_TOKEN,
        STORAGE_KEYS.TOKEN_EXPIRY,
      ]);
      const tokens = {
        accessToken: values[0][1],
        refreshToken: values[1][1],
        expiryTime: values[2][1] ? parseInt(values[2][1], 10) : null,
      };
      return tokens;
    } catch (error) {
      console.error('Failed to get tokens:', error);
      return { accessToken: null, refreshToken: null, expiryTime: null };
    }
  }

  static async clearTokens() {
    try {
      await AsyncStorage.multiRemove([
        STORAGE_KEYS.ACCESS_TOKEN,
        STORAGE_KEYS.REFRESH_TOKEN,
        STORAGE_KEYS.TOKEN_EXPIRY,
        STORAGE_KEYS.USER_INFO,
      ]);
    } catch (error) {
      console.error('Failed to clear tokens:', error);
    }
  }

  static isTokenExpired(expiryTime) {
    if (!expiryTime) return true;
    return Date.now() >= expiryTime - TOKEN_REFRESH_BUFFER_SECONDS * 1000;
  }

  static async exchangeCodeForTokens(code, codeVerifier) {
    const params = new URLSearchParams({
      grant_type: 'authorization_code',
      client_id: OAUTH_CONFIG.clientId,
      client_secret: OAUTH_CONFIG.clientSecret,
      code: code,
      redirect_uri: OAUTH_CONFIG.redirectUri,
      ...(codeVerifier && { code_verifier: codeVerifier }),
    });

    try {
      const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: params.toString(),
      });

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        throw new Error(
          errorData.error_description || errorData.error || `Token exchange failed with status ${response.status}`
        );
      }

      const tokenData = await response.json();
      const storedTokens = await TokenManager.storeTokens(
        tokenData.access_token,
        tokenData.refresh_token,
        tokenData.expires_in || 3600
      );

      return {
        ...storedTokens,
        tokenType: tokenData.token_type,
        scope: tokenData.scope,
        idToken: tokenData.id_token,
      };
    } catch (error) {
      console.error('Token exchange error:', error);
      throw error;
    }
  }

  static async refreshAccessToken(refreshToken) {
    const params = new URLSearchParams({
      grant_type: 'refresh_token',
      client_id: OAUTH_CONFIG.clientId,
      client_secret: OAUTH_CONFIG.clientSecret,
      refresh_token: refreshToken,
    });

    try {
      const response = await fetch(OAUTH_CONFIG.tokenEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: params.toString(),
      });

      if (!response.ok) {
        const errorData = await response.json().catch(() => ({}));
        if (response.status === 400 || response.status === 401) {
          await TokenManager.clearTokens();
          throw new Error('REFRESH_TOKEN_EXPIRED');
        }
        throw new Error(
          errorData.error_description || errorData.error || `Token refresh failed with status ${response.status}`
        );
      }

      const tokenData = await response.json();
      const storedTokens = await TokenManager.storeTokens(
        tokenData.access_token,
        tokenData.refresh_token || refreshToken,
        tokenData.expires_in || 3600
      );

      return storedTokens;
    } catch (error) {
      console.error('Token refresh error:', error);
      throw error;
    }
  }

  static async revokeToken(token) {
    if (!OAUTH_CONFIG.revocationEndpoint) return;

    const params = new URLSearchParams({
      token: token,
      client_id: OAUTH_CONFIG.clientId,
      client_secret: OAUTH_CONFIG.clientSecret,
    });

    try {
      await fetch(OAUTH_CONFIG.revocationEndpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/x-www-form-urlencoded',
        },
        body: params.toString(),
      });
    } catch (error) {
      console.error('Token revocation error:', error);
    }
  }

  static async getValidAccessToken() {
    const tokens = await TokenManager.getTokens();

    if (!tokens.accessToken) {
      throw new Error('NO_TOKEN');
    }

    if (!TokenManager.isTokenExpired(tokens.expiryTime)) {
      return tokens.accessToken;
    }

    if (tokens.refreshToken) {
      try {
        const newTokens = await TokenManager.refreshAccessToken(tokens.refreshToken);
        return newTokens.accessToken;
      } catch (error) {
        if (error.message === 'REFRESH_TOKEN_EXPIRED') {
          throw new Error('SESSION_EXPIRED');
        }
        throw error;
      }
    }

    throw new Error('SESSION_EXPIRED');
  }
}

// Authenticated API helper
async function authenticatedFetch(url, options = {}) {
  try {
    const accessToken = await TokenManager.getValidAccessToken();
    const response = await fetch(url, {
      ...options,
      headers: {
        ...options.headers,
        Authorization: `Bearer ${accessToken}`,
      },
    });

    if (response.status === 401) {
      const tokens = await TokenManager.getTokens();
      if (tokens.refreshToken) {
        try {
          const newTokens = await TokenManager.refreshAccessToken(tokens.refreshToken);
          const retryResponse = await fetch(url, {
            ...options,
            headers: {
              ...options.headers,
              Authorization: `Bearer ${newTokens.accessToken}`,
            },
          });
          return retryResponse;
        } catch (refreshError) {
          throw new Error('SESSION_EXPIRED');
        }
      }
      throw new Error('SESSION_EXPIRED');
    }

    return response;
  } catch (error) {
    throw error;
  }
}

// Main App Component
const discovery = {
  authorizationEndpoint: OAUTH_CONFIG.authorizationEndpoint,
  tokenEndpoint: OAUTH_CONFIG.tokenEndpoint,
  revocationEndpoint: OAUTH_CONFIG.revocationEndpoint,
};

export default function App() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [isLoading, setIsLoading] = useState(true);
  const [userInfo, setUserInfo] = useState(null);
  const [tokenInfo, setTokenInfo] = useState(null);
  const refreshTimerRef = useRef(null);

  const [request, response, promptAsync] = AuthSession.useAuthRequest(
    {
      clientId: OAUTH_CONFIG.clientId,
      scopes: OAUTH_CONFIG.scopes,
      redirectUri: OAUTH_CONFIG.redirectUri,
      responseType: AuthSession.ResponseType.Code,
      usePKCE: true,
      extraParams: {
        access_type: 'offline',
        prompt: 'consent',
      },
    },
    discovery
  );

  // Schedule automatic token refresh
  const scheduleTokenRefresh = useCallback((expiryTime) => {
    if (refreshTimerRef.current) {
      clearTimeout(refreshTimerRef.current);
    }

    const timeUntilRefresh = expiryTime - Date.now() - TOKEN_REFRESH_BUFFER_SECONDS * 1000;

    if (timeUntilRefresh > 0) {
      console.log(`Scheduling token refresh in ${Math.round(timeUntilRefresh / 1000)} seconds`);
      refreshTimerRef.current = setTimeout(async () => {
        try {
          const tokens = await TokenManager.getTokens();
          if (tokens.refreshToken) {
            console.log('Auto-refreshing access token...');
            const newTokens = await TokenManager.refreshAccessToken(tokens.refreshToken);
            setTokenInfo({
              accessToken: newTokens.accessToken ? `${newTokens.accessToken.substring(0, 20)}...` : null,
              expiryTime: new Date(newTokens.expiryTime).toLocaleString(),
              hasRefreshToken: !!newTokens.refreshToken,
            });
            scheduleTokenRefresh(newTokens.expiryTime);
          }
        } catch (error) {
          console.error('Auto token refresh failed:', error);
          if (error.message === 'REFRESH_TOKEN_EXPIRED') {
            setIsAuthenticated(false);
            setUserInfo(null);
            setTokenInfo(null);
            Alert.alert('Session Expired', 'Your session has expired. Please log in again.');
          }
        }
      }, timeUntilRefresh);
    }
  }, []);

  // Check for existing authentication on app start
  useEffect(() => {
    async function checkAuth() {
      try {
        const tokens = await TokenManager.getTokens();
        if (tokens.accessToken) {
          if (TokenManager.isTokenExpired(tokens.expiryTime) && tokens.refreshToken) {
            try {
              const newTokens = await TokenManager.refreshAccessToken(tokens.refreshToken);
              setTokenInfo({
                accessToken: newTokens.accessToken ? `${newTokens.accessToken.substring(0, 20)}...` : null,
                expiryTime: new Date(newTokens.expiryTime).toLocaleString(),
                hasRefreshToken: !!newTokens.refreshToken,
              });
              setIsAuthenticated(true);
              scheduleTokenRefresh(newTokens.expiryTime);
              await fetchUserInfo();
            } catch (error) {
              await TokenManager.clearTokens();
              setIsAuthenticated(false);
            }
          } else if (!TokenManager.isTokenExpired(tokens.expiryTime)) {
            setTokenInfo({
              accessToken: tokens.accessToken ? `${tokens.accessToken.substring(0, 20)}...` : null,
              expiryTime: new Date(tokens.expiryTime).toLocaleString(),
              hasRefreshToken: !!tokens.refreshToken,
            });
            setIsAuthenticated(true);
            scheduleTokenRefresh(tokens.expiryTime);
            await fetchUserInfo();
          } else {
            await TokenManager.clearTokens();
          }
        }
      } catch (error) {
        console.error('Auth check error:', error);
      } finally {
        setIsLoading(false);
      }
    }
    checkAuth();

    return () => {
      if (refreshTimerRef.current) {
        clearTimeout(refreshTimerRef.current);
      }
    };
  }, [scheduleTokenRefresh]);

  // Handle OAuth response
  useEffect(() => {
    async function handleResponse() {
      if (response?.type === 'success') {
        const { code } = response.params;
        try {
          setIsLoading(true);
          const tokenResult = await TokenManager.exchangeCodeForTokens(
            code,
            request?.codeVerifier
          );
          setTokenInfo({
            accessToken: tokenResult.accessToken ? `${tokenResult.accessToken.substring(0, 20)}...` : null,
            expiryTime: new Date(tokenResult.expiryTime).toLocaleString(),
            hasRefreshToken: !!tokenResult.refreshToken,
          });
          setIsAuthenticated(true);
          scheduleTokenRefresh(tokenResult.expiryTime);
          await fetchUserInfo();
        } catch (error) {
          Alert.alert('Authentication Error', error.message || 'Failed to exchange authorization code for tokens.');
        } finally {
          setIsLoading(false);
        }
      } else if (response?.type === 'error') {
        Alert.alert(
          'Authentication Error',
          response.error?.message || 'An error occurred during authentication.'
        );
      }
    }
    handleResponse();
  }, [response, request, scheduleTokenRefresh]);

  const fetchUserInfo = async () => {
    try {
      const res = await authenticatedFetch(OAUTH_CONFIG.userInfoEndpoint);
      if (res.ok) {
        const data = await res.json();
        setUserInfo(data);
        await AsyncStorage.setItem(STORAGE_KEYS.USER_INFO, JSON.stringify(data));
      }
    } catch (error) {
      console.error('Failed to fetch user info:', error);
      // Try to load cached user info
      try {
        const cached = await AsyncStorage.getItem(STORAGE_KEYS.USER_INFO);
        if (cached) {
          setUserInfo(JSON.parse(cached));
        }
      } catch (cacheError) {
        console.error('Failed to load cached user info:', cacheError);
      }
    }
  };

  const handleLogin = async () => {
    try {
      await promptAsync();
    } catch (error) {
      Alert.alert('Login Error', error.message || 'Failed to start authentication flow.');
    }
  };

  const handleLogout = async () => {
    try {
      setIsLoading(true);
      const tokens = await TokenManager.getTokens();

      // Revoke tokens
      if (tokens.refreshToken) {
        await TokenManager.revokeToken(tokens.refreshToken);
      }
      if (tokens.accessToken) {
        await TokenManager.revokeToken(tokens.accessToken);
      }

      // Clear stored tokens
      await TokenManager.clearTokens();

      // Clear refresh timer
      if (refreshTimerRef.current) {
        clearTimeout(refreshTimerRef.current);
      }

      setIsAuthenticated(false);
      setUserInfo(null);
      setTokenInfo(null);
    } catch (error) {
      console.error('Logout error:', error);
      // Clear local state even if revocation fails
      await TokenManager.clearTokens();
      setIsAuthenticated(false);
      setUserInfo(null);
      setTokenInfo(null);
    } finally {
      setIsLoading(false);
    }
  };

  const handleManualRefresh = async () => {
    try {
      setIsLoading(true);
      const tokens = await TokenManager.getTokens();
      if (tokens.refreshToken) {
        const newTokens = await TokenManager.refreshAccessToken(tokens.refreshToken);
        setTokenInfo({
          accessToken: newTokens.accessToken ? `${newTokens.accessToken.substring(0, 20)}...` : null,
          expiryTime: new Date(newTokens.expiryTime).toLocaleString(),
          hasRefreshToken: !!newTokens.refreshToken,
        });
        scheduleTokenRefresh(newTokens.expiryTime);
        Alert.alert('Success', 'Token refreshed successfully!');
      } else {
        Alert.alert('Error', 'No refresh token available.');
      }
    } catch (error) {
      Alert.alert('Refresh Error', error.message || 'Failed to refresh token.');
      if (error.message === 'REFRESH_TOKEN_EXPIRED') {
        setIsAuthenticated(false);
        setUserInfo(null);
        setTokenInfo(null);
      }
    } finally {
      setIsLoading(false);
    }
  };

  const handleTestApiCall = async () => {
    try {
      setIsLoading(true);
      const res = await authenticatedFetch(OAUTH_CONFIG.userInfoEndpoint);
      if (res.ok) {
        const data = await res.json();
        setUserInfo(data);
        Alert.alert('API Call Success', 'User info fetched successfully with valid token.');
      } else {
        Alert.alert('API Call Failed', `Status: ${res.status}`);
      }
    } catch (error) {
      if (error.message === 'SESSION_EXPIRED' || error.message === 'NO_TOKEN') {
        Alert.alert('Session Expired', 'Please log in again.');
        setIsAuthenticated(false);
        setUserInfo(null);
        setTokenInfo(null);
      } else {
        Alert.alert('API Error', error.message);
      }
    } finally {
      setIsLoading(false);
    }
  };

  if (isLoading) {
    return (
      <View style={styles.centered}>
        <ActivityIndicator size="large" color="#4A90D9" />
        <Text style={styles.loadingText}>Loading...</Text>
      </View>
    );
  }

  if (!isAuthenticated) {
    return (
      <View style={styles.container}>
        <View style={styles.loginContainer}>
          <Text style={styles.appTitle}>My App</Text>
          <Text style={styles.subtitle}>Cross-Platform Mobile Application</Text>

          <View style={styles.warningBox}>
            <Text style={styles.warningTitle}>⚠️ Security Notice</Text>
            <Text style={styles.warningText}>
              This app includes client_secret in the configuration for demonstration purposes.
              In production, mobile apps should use Authorization Code Flow with PKCE without
              a client_secret, or route token exchange through a secure backend.
            </Text>
          </View>

          <TouchableOpacity
            style={[styles.button, styles.loginButton]}
            onPress={handleLogin}
            disabled={!request}
          >
            <Text style={styles.buttonText}>Sign In with OAuth</Text>
          </TouchableOpacity>

          <Text style={styles.redirectInfo}>
            Redirect URI: {OAUTH_CONFIG.redirectUri}
          </Text>
        </View>
      </View>
    );
  }

  return (
    <ScrollView style={styles.container} contentContainerStyle={styles.scrollContent}>
      <View style={styles.header}>
        <Text style={styles.headerTitle}>Welcome!</Text>
        {userInfo && (
          <Text style={styles.headerSubtitle}>
            {userInfo.name || userInfo.preferred_username || userInfo.email || 'User'}
          </Text>
        )}
      </View>

      {userInfo && (
        <View style={styles.card}>
          <Text style={styles.cardTitle}>User Information</Text>
          {userInfo.name && (
            <View style={styles.infoRow}>
              <Text style={styles.infoLabel}>Name:</Text>
              <Text style={styles.infoValue}>{userInfo.name}</Text>
            </View>
          )}
          {userInfo.email && (
            <View style={styles.infoRow}>
              <Text style={styles.infoLabel}>Email:</Text>
              <Text style={styles.infoValue}>{userInfo.email}</Text>
            </View>
          )}
          {userInfo.sub && (
            <View style={styles.infoRow}>
              <Text style={styles.infoLabel}>Subject:</Text>
              <Text style={styles.infoValue}>{userInfo.sub}</Text>
            </View>
          )}
        </View>
      )}

      {tokenInfo && (
        <View style={styles.card}>
          <Text style={styles.cardTitle}>Token Information</Text>
          <View style={styles.infoRow}>
            <Text style={styles.infoLabel}>Access Token:</Text>
            <Text style={styles.infoValue}>{tokenInfo.accessToken}</Text>
          </View>
          <View style={styles.infoRow}>
            <Text style={styles.infoLabel}>Expires:</Text>
            <Text style={styles.infoValue}>{tokenInfo.expiryTime}</Text>
          </View>
          <View style={styles.infoRow}>
            <Text style={styles.infoLabel}>Refresh Token:</Text>
            <Text style={styles.infoValue}>
              {tokenInfo.hasRefreshToken ? '✅ Available' : '❌ Not available'}
            </Text>
          </View>
        </View>
      )}

      <View style={styles.actionsContainer}>
        <TouchableOpacity
          style={[styles.button, styles.refreshButton]}
          onPress={handleManualRefresh}
        >
          <Text style={styles.buttonText}>Refresh Token</Text>
        </TouchableOpacity>

        <TouchableOpacity
          style={[styles.button, styles.apiButton]}
          onPress={handleTestApiCall}
        >
          <Text style={styles.buttonText}>Test API Call</Text>
        </TouchableOpacity>

        <TouchableOpacity
          style={[styles.button, styles.logoutButton]}
          onPress={handleLogout}
        >
          <Text style={styles.buttonText}>Sign Out</Text>
        </TouchableOpacity>
      </View>
    </ScrollView>
  );
}

